<?php
/**
 * Inline SVG sprite — incluir una sola vez al inicio del <body>.
 * Define todos los iconos como <symbol> para referenciarse con <use href="#icon-X">.
 * $icons viene del scope de loadView (AppController).
 */
foreach ($icons as $iconName => $svgMarkup) {
    preg_match("/viewBox='([^']+)'/", $svgMarkup, $vbMatch);
    $viewBox = $vbMatch[1] ?? '0 0 24 24';
    preg_match("/fill='([^']+)'/", $svgMarkup, $fillMatch);
    $fillAttr = isset($fillMatch[1]) ? ' fill="' . htmlspecialchars($fillMatch[1], ENT_QUOTES, 'UTF-8') . '"' : '';
    $inner = preg_replace('/<svg[^>]*>/i', '', $svgMarkup, 1);
    $inner = trim(preg_replace('/<\/svg>\s*$/i', '', $inner));
    $symbols[] = '<symbol id="icon-' . htmlspecialchars($iconName, ENT_QUOTES, 'UTF-8') . '" viewBox="' . htmlspecialchars($viewBox, ENT_QUOTES, 'UTF-8') . '"' . $fillAttr . '>' . $inner . '</symbol>';
}
?>
